  meta='{"propertyDescriptors":[{"id":"isActive","filterable":true,"sortable":true},{"id":"_actions","displayer":{"id":"actions","actions":["edit","delete","consoleLog"]}}]}'
  layouts="table"}}
{
  "actions": {
    "edit": {
      "icon": "pencil",
      "label": "Edit",
      "action": "edit"
    },
    "delete": {
      "icon": "trash",
      "label": "Delete Space",
      "action": "delete",
      "confirm": "Are you sure you want to delete this entire space?"
    },
    "consoleLog": {
      "icon": "console",
      "label": "Log Tour",
      "action": "custom",
      "onclick": "console.log('Tour clicked:', this.row.data); return false;"
    }
  }
}
{{/liveData}}
